  2	import { Link } from 'react-router-dom-v5-compat';
  3	import xbytes from 'xbytes';
  4	
  5	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
  6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  7	import { isEmpty } from '@kubevirt-utils/utils/utils';
  8	import { PrometheusEndpoint, usePrometheusPoll } from '@openshift-console/dynamic-plugin-sdk';
  9	import {
 10	  Chart,
 11	  ChartArea,
 12	  ChartAxis,
 13	  ChartGroup,
 14	  ChartVoronoiContainer,
 15	} from '@patternfly/react-charts';
 16	import chart_color_black_200 from '@patternfly/react-tokens/dist/esm/chart_color_black_200';
 17	import chart_color_blue_300 from '@patternfly/react-tokens/dist/esm/chart_color_blue_300';
 18	import chart_color_green_300 from '@patternfly/react-tokens/dist/esm/chart_color_green_300';
 19	import chart_color_orange_300 from '@patternfly/react-tokens/dist/esm/chart_color_orange_300';
 20	import useDuration from '@virtualmachines/details/tabs/metrics/hooks/useDuration';
 21	
 22	import { tickLabels } from '../ChartLabels/styleOverrides';
 23	import ComponentReady from '../ComponentReady/ComponentReady';
 24	import useResponsiveCharts from '../hooks/useResponsiveCharts';
 25	import { getUtilizationQueries } from '../utils/queries';
 26	import {
 27	  findMigrationMaxYValue,
 28	  formatMemoryYTick,
 29	  getPrometheusData,
 30	  MILLISECONDS_MULTIPLIER,
 31	  queriesToLink,
 32	  tickFormat,
 33	  TICKS_COUNT,
 34	} from '../utils/utils';
 35	
 36	type MigrationThresholdChartProps = {
 37	  vmi: V1VirtualMachineInstance;
 38	};
 39	
 40	const MigrationThresholdChart: React.FC<MigrationThresholdChartProps> = ({ vmi }) => {
 41	  const { t } = useKubevirtTranslation();
 42	  const { currentTime, duration, timespan } = useDuration();
 43	  const queries = useMemo(() => getUtilizationQueries({ duration, obj: vmi }), [vmi, duration]);
 44	  const { height, ref, width } = useResponsiveCharts();
 45	
 46	  const [migrationDataProcessed] = usePrometheusPoll({
 47	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
 48	    endTime: currentTime,
 49	    namespace: vmi?.metadata?.namespace,
 50	    query: queries?.MIGRATION_DATA_PROCESSED,
 51	    timespan,
 52	  });
 53	
 54	  const [migrationDataRemaining] = usePrometheusPoll({
 55	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
 56	    endTime: currentTime,
 57	    namespace: vmi?.metadata?.namespace,
 58	    query: queries?.MIGRATION_DATA_REMAINING,
 59	    timespan,
 60	  });
 61	
 62	  const [migrationDataDirtyRate] = usePrometheusPoll({
 63	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
 64	    endTime: currentTime,
 65	    namespace: vmi?.metadata?.namespace,
 66	    query: queries?.MIGRATION_MEMORY_DIRTY_RATE,
 67	    timespan,
 68	  });
 69	
 70	  const dataProcessed = useMemo(
 71	    () => getPrometheusData(migrationDataProcessed),
 72	    [migrationDataProcessed],
 73	  );
 74	  const dataRemaining = useMemo(
 75	    () => getPrometheusData(migrationDataRemaining),
 76	    [migrationDataRemaining],
 77	  );
 78	  const dataDirtyRate = useMemo(
 79	    () => getPrometheusData(migrationDataDirtyRate),
 80	    [migrationDataDirtyRate],
 81	  );
 82	
 83	  const chartDataProcessed = dataProcessed?.map(([x, y]) => {
 84	    return { name: t('Data Processed'), x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) };
 85	  });
 86	
 87	  const chartDataRemaining = dataRemaining?.map(([x, y]) => {
 88	    return { name: t('Data Remaining'), x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) };
 89	  });
 90	
 91	  const chartDataDirtyRate = dataDirtyRate?.map(([x, y]) => {
 92	    return { name: t('Memory Dirty Rate'), x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) };
 93	  });
 94	
 95	  const isReady =
 96	    !isEmpty(chartDataProcessed) || !isEmpty(chartDataRemaining) || !isEmpty(chartDataDirtyRate);
 97	  const yMax = findMigrationMaxYValue(chartDataProcessed, chartDataRemaining, chartDataDirtyRate);
 98	  const linkToMetrics = queriesToLink([
 99	    queries?.MIGRATION_DATA_REMAINING,
100	    queries.MIGRATION_DATA_PROCESSED,
101	    queries.MIGRATION_MEMORY_DIRTY_RATE,
102	  ]);
103	  return (
104	    <ComponentReady isReady={isReady} linkToMetrics={linkToMetrics}>
105	      <div className="util-threshold-chart" ref={ref}>
106	        <Link to={linkToMetrics}>
107	          <Chart
108	            containerComponent={
109	              <ChartVoronoiContainer
110	                labels={({ datum }) => {
111	                  return `${datum?.name}: ${xbytes(datum?.y, { fixed: 2, iec: true })}`;
112	                }}
113	                constrainToVisibleArea
114	              />
115	            }
116	            domain={{
117	              x: [currentTime - timespan, currentTime],
118	              y: [0, yMax],
119	            }}
120	            legendData={[
121	              { name: t('Data Processed') },
122	              { name: t('Data Remaining'), symbol: { fill: chart_color_green_300.value } },
123	              { name: t('Memory Dirty Rate'), symbol: { fill: chart_color_orange_300.value } },
124	            ]}
125	            height={height}
126	            legendOrientation="horizontal"
127	            legendPosition="bottom"
128	            padding={{ bottom: 55, left: 35, right: 35, top: 25 }}
129	            scale={{ x: 'time', y: 'linear' }}
130	            width={width}
131	          >
132	            <ChartAxis
133	              style={{
134	                grid: {
135	                  stroke: chart_color_black_200.value,
136	                },
137	                tickLabels,
138	              }}
139	              dependentAxis
140	              tickFormat={formatMemoryYTick(yMax, 2)}
141	              tickValues={[0, yMax]}
142	            />
143	            <ChartAxis
144	              style={{
145	                tickLabels: { padding: 2, ...tickLabels },
146	                ticks: { stroke: 'transparent' },
147	              }}
148	              axisComponent={<></>}
149	              tickCount={TICKS_COUNT}
150	              tickFormat={tickFormat(duration, currentTime)}
151	            />
152	            <ChartGroup>
153	              <ChartArea
154	                style={{
155	                  data: {
156	                    stroke: chart_color_blue_300.value,
157	                  },
158	                }}
159	                data={chartDataProcessed}
160	              />
161	              <ChartArea
162	                style={{
163	                  data: {
164	                    stroke: chart_color_green_300.value,
165	                  },
166	                }}
167	                data={chartDataRemaining}
168	              />
169	              <ChartArea
170	                style={{
171	                  data: {
172	                    stroke: chart_color_orange_300?.value,
173	                  },
174	                }}
175	                data={chartDataDirtyRate}
176	              />
177	            </ChartGroup>
178	          </Chart>
179	        </Link>
180	      </div>
181	    </ComponentReady>
182	  );
183	};
184	
185	export default MigrationThresholdChart;

